/* Drawflow - Minimal loader using CDN */
/* For full Drawflow library, see: https://github.com/jerosoler/Drawflow */
(function(window) {
    'use strict';
    
    var Drawflow = function(id, parent) {
        this.id = id;
        this.parent = parent;
        this.canvas = document.getElementById(id);
        this.nodes = [];
        this.connections = [];
        this.drawflow = { drawflow: { Home: { data: {} } } };
        this.events = {};
        this.module = 'Home';
        this.mode = 'edit';
        this._nodeSeq = 0;
        this._connSeq = 0;
        
        if (this.canvas) {
            this.canvas.classList.add('drawflow');
        }
    };
    
    Drawflow.prototype.addNode = function(name, inputs, outputs, data, position) {
        this._nodeSeq += 1;
        var node = {
            id: 'node-' + Date.now() + '-' + this._nodeSeq,
            name: name,
            data: data,
            inputs: inputs,
            outputs: outputs,
            position: position
        };
        this.nodes.push(node);
        return node.id;
    };
    
    Drawflow.prototype.addConnection = function(output_id, input_id, output_name, input_name) {
        this._connSeq += 1;
        var connection = {
            id: 'conn-' + Date.now() + '-' + this._connSeq,
            output_id: output_id,
            input_id: input_id,
            output_name: output_name,
            input_name: input_name
        };
        this.connections.push(connection);
        return connection.id;
    };
    
    Drawflow.prototype.removeNode = function(node_id) {
        this.nodes = this.nodes.filter(n => n.id !== node_id);
    };
    
    Drawflow.prototype.removeConnection = function(conn_id) {
        this.connections = this.connections.filter(c => c.id !== conn_id);
    };
    
    Drawflow.prototype.export = function() {
        return JSON.stringify(this.drawflow, null, 2);
    };
    
    Drawflow.prototype.import = function(data) {
        try {
            this.drawflow = typeof data === 'string' ? JSON.parse(data) : data;
        } catch(e) {
            console.error('Invalid JSON:', e);
        }
    };
    
    Drawflow.prototype.on = function(event, callback) {
        if (!this.events[event]) {
            this.events[event] = [];
        }
        this.events[event].push(callback);
    };
    
    Drawflow.prototype.emit = function(event, data) {
        if (this.events[event]) {
            this.events[event].forEach(cb => cb(data));
        }
    };
    
    Drawflow.prototype.getNodes = function() {
        return this.nodes;
    };
    
    Drawflow.prototype.getConnections = function() {
        return this.connections;
    };
    
    Drawflow.prototype.clear = function() {
        this.nodes = [];
        this.connections = [];
        this.drawflow = { drawflow: { Home: { data: {} } } };
    };
    
    // Export to window
    window.Drawflow = Drawflow;
    
    // Intentionally avoid CDN override here.
    // The workflow builder depends on this shim's constructor/method signatures.
    
})(window);